-- create database aeroxv5;
-- use aeroxv5;
-- drop database aeroxv5;
-- =====================================================================
-- 1. AIRPORT 
-- =====================================================================

CREATE TABLE aircraft (
    aircraft_id INT PRIMARY KEY AUTO_INCREMENT,
    model_code VARCHAR(10) NOT NULL,
    model_name VARCHAR(50) NOT NULL,
    manufacturer VARCHAR(50) NOT NULL,
    manufacturing_dt DATE,
    aircraft_capacity INT NOT NULL,
    fuel_capacity DECIMAL(10,2),
    aircraft_status ENUM('active', 'maintenance', 'retired', 'leased_out', 'scrapped') DEFAULT 'active',
    last_servicing_dt DATE,
    next_servicing_dt DATE,
    is_active BOOLEAN DEFAULT TRUE
);

-- ==========================================
-- 2. AIRPORT TABLE
-- ==========================================
CREATE TABLE airport (
    airport_id INT PRIMARY KEY AUTO_INCREMENT,
    airport_name VARCHAR(50) NOT NULL,
    city VARCHAR(30) NOT NULL,
    country VARCHAR(20) NOT NULL,
    timezone VARCHAR(50) NOT NULL,
    is_active BOOLEAN DEFAULT TRUE
);

-- ==========================================
-- 3. PASSENGER TABLE 
-- ==========================================
CREATE TABLE passenger (
    passenger_id INT PRIMARY KEY AUTO_INCREMENT,
    first_name VARCHAR(50) NOT NULL,
    last_name VARCHAR(50) NOT NULL,
    date_of_birth DATE NOT NULL,
    gender ENUM('Male','Female','Other') NOT NULL,
    email VARCHAR(100),
    phone_number VARCHAR(20),
    passport_number VARCHAR(20) UNIQUE NOT NULL,
    passport_expiry_date DATE,
    nationality VARCHAR(50) NOT NULL,
    address TEXT,
    city VARCHAR(50),
    state VARCHAR(50),
    postal_code VARCHAR(20),
    emergency_contact_name VARCHAR(100),
    emergency_contact_phone VARCHAR(20),
    medical_conditions TEXT,
    is_active BOOLEAN DEFAULT TRUE,
    registration_date TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

-- ==========================================
-- 4. FLIGHT TABLE
-- ==========================================
CREATE TABLE flight (
    flight_id INT PRIMARY KEY AUTO_INCREMENT,
    flight_code VARCHAR(10) NOT NULL UNIQUE,
    flight_name VARCHAR(50) NOT NULL,
    aircraft_id INT NOT NULL,
    base_airport_id INT NOT NULL,
    origin_airport_id INT NOT NULL,
    destination_airport_id INT NOT NULL,
    flight_type ENUM('Passenger', 'Cargo', 'Charter', 'Ferry') DEFAULT 'Passenger',
    flight_scope ENUM('Domestic', 'International', 'Regional', 'Intercontinental') NOT NULL,
    standard_departure_time TIME,
    standard_arrival_time TIME,
    total_distance_km DECIMAL(10,2),
    is_active BOOLEAN DEFAULT TRUE,
    FOREIGN KEY (aircraft_id) REFERENCES aircraft(aircraft_id) ON DELETE RESTRICT,
    FOREIGN KEY (base_airport_id) REFERENCES airport(airport_id) ON DELETE RESTRICT,
    FOREIGN KEY (origin_airport_id) REFERENCES airport(airport_id) ON DELETE RESTRICT,
    FOREIGN KEY (destination_airport_id) REFERENCES airport(airport_id) ON DELETE RESTRICT
);

-- ==========================================
-- 5. TRIP_DETAILS TABLE
-- ==========================================
CREATE TABLE trip_details (
    trip_id INT PRIMARY KEY AUTO_INCREMENT,
    flight_id INT NOT NULL,
    origin_airport_id INT NOT NULL,
    destination_airport_id INT NOT NULL,
    scheduled_departure DATETIME NOT NULL,
    scheduled_arrival DATETIME NOT NULL,
    actual_departure DATETIME,
    actual_arrival DATETIME,
    trip_status ENUM('Scheduled', 'Boarding', 'Departed', 'In Air', 'Arrived', 'Delayed', 'Cancelled', 'Diverted') DEFAULT 'Scheduled',
    gate_departure VARCHAR(10) NOT NULL,
    gate_arrival VARCHAR(10),
    terminal_departure VARCHAR(10) NOT NULL,
    terminal_arrival VARCHAR(10),
    delay_minutes INT DEFAULT 0,
    delay_reason VARCHAR(255),
    cancellation_reason TEXT,
    is_international BOOLEAN DEFAULT FALSE,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
    FOREIGN KEY (flight_id) REFERENCES flight(flight_id) ON DELETE RESTRICT,
    FOREIGN KEY (origin_airport_id) REFERENCES airport(airport_id) ON DELETE RESTRICT,
    FOREIGN KEY (destination_airport_id) REFERENCES airport(airport_id) ON DELETE RESTRICT
);

-- ==========================================
-- 6. CREW TABLE (Consolidated with assignment fields)
-- ==========================================
CREATE TABLE crew (
    crew_id INT PRIMARY KEY AUTO_INCREMENT,
    staff_code VARCHAR(10) UNIQUE NOT NULL,
    first_name VARCHAR(50) NOT NULL,
    last_name VARCHAR(50) NOT NULL,
    role ENUM('Captain', 'First Officer', 'Lead Cabin Crew', 'Flight Attendant') NOT NULL,
    license_number VARCHAR(20),
    license_expiry_date DATE,
    years_of_experience INT,
    nationality VARCHAR(30) NOT NULL,
    last_safety_check DATETIME,
    next_safety_check_due DATE,
    gender ENUM('Male','Female','Other') NOT NULL,
    is_active BOOLEAN DEFAULT TRUE,
    -- Assignment fields (directly in crew table)
    current_trip_id INT NULL,
    assignment_role ENUM('Captain', 'First Officer', 'Lead Cabin Crew', 'Flight Attendant') NULL,
    check_in_time DATETIME NULL,
    check_out_time DATETIME NULL,
    assigned_at TIMESTAMP NULL,
    FOREIGN KEY (current_trip_id) REFERENCES trip_details(trip_id) ON DELETE SET NULL
);

-- ==========================================
-- 7. BOOKING_INFO TABLE
-- ==========================================
CREATE TABLE booking_info (
    booking_id BIGINT PRIMARY KEY AUTO_INCREMENT,
    booking_reference VARCHAR(6) UNIQUE NOT NULL,
    trip_id INT NOT NULL,
    passenger_id INT NOT NULL,
    booking_date DATETIME DEFAULT CURRENT_TIMESTAMP,
    booking_status ENUM('Confirmed', 'Pending', 'Cancelled', 'Completed', 'No-Show') DEFAULT 'Confirmed',
    travel_class ENUM('Economy', 'Premium Economy', 'Business', 'First') NOT NULL,
    seat_number VARCHAR(5),
    fare DECIMAL(10,2) NOT NULL,
    extra_baggage_kg INT DEFAULT 0,
    baggage_fee DECIMAL(8,2) DEFAULT 0,
    meal_preference ENUM('Standard', 'Vegetarian', 'Non-Veg', 'Vegan', 'Gluten-Free') DEFAULT 'Standard',
    special_assistance ENUM('None', 'Wheelchair', 'Infant', 'Elderly', 'Medical') DEFAULT 'None',
    ticket_cancellation_flag BOOLEAN DEFAULT FALSE,
    cancellation_date DATETIME,
    payment_status ENUM('Pending', 'Paid', 'Failed', 'Refunded') DEFAULT 'Pending',
    payment_method ENUM('Credit Card', 'Debit Card', 'UPI', 'Net Banking', 'Wallet'),
    boarding_pass_issued BOOLEAN DEFAULT FALSE,
    booking_channel ENUM('Website', 'Mobile App', 'Agent', 'API') DEFAULT 'Website',
    FOREIGN KEY (trip_id) REFERENCES trip_details(trip_id) ON DELETE RESTRICT,
    FOREIGN KEY (passenger_id) REFERENCES passenger(passenger_id) ON DELETE RESTRICT
);

-- ==========================================
-- 8. REVIEW TABLE
-- ==========================================
CREATE TABLE review (
    review_id INT PRIMARY KEY AUTO_INCREMENT,
    booking_id BIGINT NOT NULL,
    passenger_id INT NOT NULL,
    flight_id INT NULL,                       
    crew_id INT NULL,                         
    review_type ENUM('flight', 'crew') NOT NULL DEFAULT 'flight',
    rating INT CHECK (rating BETWEEN 1 AND 5),
    title VARCHAR(100),
    comment TEXT,
    review_date TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    cleanliness_rating INT CHECK (cleanliness_rating BETWEEN 1 AND 5),
    service_rating INT CHECK (service_rating BETWEEN 1 AND 5),
    entertainment_rating INT CHECK (entertainment_rating BETWEEN 1 AND 5),
    food_rating INT CHECK (food_rating BETWEEN 1 AND 5),
    is_verified BOOLEAN DEFAULT FALSE,
    is_public BOOLEAN DEFAULT TRUE,
    response_from_airline TEXT,
    response_date TIMESTAMP NULL,
    UNIQUE KEY unique_booking_review (booking_id),
    FOREIGN KEY (booking_id) REFERENCES booking_info(booking_id) ON DELETE CASCADE,
    FOREIGN KEY (passenger_id) REFERENCES passenger(passenger_id) ON DELETE RESTRICT,
    FOREIGN KEY (flight_id) REFERENCES flight(flight_id) ON DELETE RESTRICT,
    FOREIGN KEY (crew_id) REFERENCES crew(crew_id) ON DELETE SET NULL
);
-- ==========================================
-- 9. REVENUE_TRACKING TABLE
-- ==========================================
CREATE TABLE revenue_tracking (
    revenue_id INT PRIMARY KEY AUTO_INCREMENT,
    booking_id BIGINT NOT NULL,
    base_fare DECIMAL(10,2) NOT NULL,
    tax_amount DECIMAL(10,2) NOT NULL,
    ancillary_fees DECIMAL(10,2) DEFAULT 0,
    total_revenue DECIMAL(10,2) NOT NULL,
    operating_cost DECIMAL(10,2) NOT NULL,
    net_profit DECIMAL(10,2),
    currency_code CHAR(3) DEFAULT 'USD',
    payment_gateway_fee DECIMAL(8,2) DEFAULT 0,
    transaction_id VARCHAR(50),
    transaction_date TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (booking_id) REFERENCES booking_info(booking_id) ON DELETE RESTRICT
);




